 1	import React, { FC } from 'react';
 2	import { useTranslation } from 'react-i18next';
 3	
 4	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 5	import Status from '@openshift-console/dynamic-plugin-sdk/lib/app/components/status/Status';
 6	import { Tooltip } from '@patternfly/react-core';
 7	import { ConnectedIcon } from '@patternfly/react-icons/dist/esm/icons/connected-icon';
 8	import { DisconnectedIcon } from '@patternfly/react-icons/dist/esm/icons/disconnected-icon';
 9	import Loading from '@utils/components/Loading/Loading';
10	import { EndPointSliceModel } from '@utils/models';
11	import { EndpointSliceKind } from '@utils/types';
12	
13	export type PodTrafficProp = {
14	  namespace: string;
15	  podName: string;
16	  tooltipFlag?: boolean;
17	};
18	
19	export const PodTraffic: FC<PodTrafficProp> = ({ namespace, podName, tooltipFlag }) => {
20	  const { t } = useTranslation();
21	  const [data, loaded, loadError] = useK8sWatchResource<EndpointSliceKind[]>({
22	    groupVersionKind: {
23	      kind: EndPointSliceModel.kind,
24	      version: EndPointSliceModel.apiVersion,
25	    },
26	    isList: true,
27	    namespace,
28	    namespaced: true,
29	  });
30	
31	  if (!loaded) {
32	    return <Loading />;
33	  } else if (loaded && loadError) {
34	    return <Status status="Error" title={t('Error')} />;
35	  }
36	  const allEndpoints = data?.reduce((prev, next) => prev.concat(next?.endpoints), []);
37	  const receivingTraffic = allEndpoints?.some((endPoint) => endPoint?.targetRef?.name === podName);
38	  if (tooltipFlag) {
39	    return (
40	      loaded &&
41	      !loadError && (
42	        <div data-test="pod-traffic-status">
43	          <Tooltip
44	            content={receivingTraffic ? t('Receiving Traffic') : t('Not Receiving Traffic')}
45	            position="top"
46	          >
47	            {receivingTraffic ? <ConnectedIcon /> : <DisconnectedIcon />}
48	          </Tooltip>
49	        </div>
50	      )
51	    );
52	  }
53	  return loaded && !loadError && (receivingTraffic ? <ConnectedIcon /> : <DisconnectedIcon />);
54	};

